import React, { useState, useCallback } from 'react';
import { BrowserRouter, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, useAuth } from './hooks/useAuth';
import { useWebSocket } from './hooks/useWebSocket';
import Sidebar from './components/Sidebar';
import AlertPopup from './components/AlertPopup';
import LoginPage from './pages/LoginPage';
import DashboardPage from './pages/DashboardPage';
import DevicesPage from './pages/DevicesPage';
import EndpointsPage from './pages/EndpointsPage';
import AlertsPage from './pages/AlertsPage';
import PolicyPage from './pages/PolicyPage';

function ProtectedLayout() {
  const { user } = useAuth();
  const [liveEvents, setLiveEvents] = useState([]);
  const [popups, setPopups]         = useState([]);
  const [alertCount, setAlertCount] = useState(0);

  const handleWs = useCallback((msg) => {
    if (msg.type === 'device_event') {
      setLiveEvents(p => [...p.slice(-49), msg.data]);
    }
    if (msg.type === 'device_alert') {
      const id = Date.now();
      setPopups(p => [...p.slice(-3), { ...msg.data, _id: id }]);
      setAlertCount(c => c + 1);
    }
  }, []);

  useWebSocket(handleWs);

  if (!user) return <Navigate to="/login" replace />;

  return (
    <div style={{ display: 'flex', minHeight: '100vh', background: 'var(--bg-void)' }}>
      <Sidebar alertCount={alertCount} />

      {/* Main content */}
      <main style={{
        flex: 1, marginLeft: '220px',
        padding: '28px 28px',
        minHeight: '100vh',
        background: 'var(--bg-void)',
        position: 'relative',
      }}>
        {/* Subtle grid background */}
        <div style={{
          position: 'fixed', inset: 0, marginLeft: '220px', pointerEvents: 'none', zIndex: 0,
          backgroundImage: 'linear-gradient(rgba(0,212,255,0.02) 1px, transparent 1px), linear-gradient(90deg, rgba(0,212,255,0.02) 1px, transparent 1px)',
          backgroundSize: '40px 40px',
        }} />

        <div style={{ position: 'relative', zIndex: 1 }}>
          <Routes>
            <Route path="/"          element={<DashboardPage liveEvents={liveEvents} />} />
            <Route path="/devices"   element={<DevicesPage   liveEvents={liveEvents} />} />
            <Route path="/endpoints" element={<EndpointsPage liveEvents={liveEvents} />} />
            <Route path="/alerts"    element={<AlertsPage    liveEvents={liveEvents} onAlertCountChange={setAlertCount} />} />
            <Route path="/policy"    element={<PolicyPage />} />
            <Route path="*"          element={<Navigate to="/" replace />} />
          </Routes>
        </div>
      </main>

      {/* Alert popups */}
      <div style={{ position: 'fixed', bottom: '20px', right: '20px', zIndex: 300, display: 'flex', flexDirection: 'column', gap: '10px' }}>
        {popups.map(popup => (
          <AlertPopup key={popup._id} alert={popup} onClose={() => setPopups(p => p.filter(x => x._id !== popup._id))} />
        ))}
      </div>
    </div>
  );
}

function AppRoutes() {
  const { loading } = useAuth();
  if (loading) return (
    <div style={{ minHeight: '100vh', background: 'var(--bg-void)', display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
      <div style={{ width: '40px', height: '40px', border: '2px solid rgba(0,212,255,0.2)', borderTop: '2px solid var(--accent-blue)', borderRadius: '50%', animation: 'spin 0.8s linear infinite' }} />
      <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
    </div>
  );
  return (
    <Routes>
      <Route path="/login" element={<LoginPage />} />
      <Route path="/*"     element={<ProtectedLayout />} />
    </Routes>
  );
}

export default function App() {
  return (
    <AuthProvider>
      <BrowserRouter><AppRoutes /></BrowserRouter>
    </AuthProvider>
  );
}
